func Test_WsUpgradeHandshake(t *testing.T) {
	// Tests WebSocket upgrade returns 101 Switching Protocols with correct Sec-WebSocket-Accept header
	baseURL := os.Getenv("SUT_URL")
	if baseURL == "" {
		baseURL = "http://127.0.0.1:8012"
	}
	body := strings.NewReader("")
	req, err := http.NewRequest("GET", baseURL+"/fixtures/ws_upgrade_handshake/ws", body)
	if err != nil {
		t.Fatalf("new request failed: %v", err)
	}
	req.Header.Set(`Connection`, `Upgrade`)
	req.Header.Set(`Sec-WebSocket-Key`, `dGhlIHNhbXBsZSBub25jZQ==`)
	req.Header.Set(`Sec-WebSocket-Version`, `13`)
	req.Header.Set(`Upgrade`, `websocket`)
	noRedirectClient := &http.Client{
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			return http.ErrUseLastResponse
		},
	}
	resp, err := noRedirectClient.Do(req)
	if err != nil {
		t.Fatalf("request failed: %v", err)
	}
	defer func() { _ = resp.Body.Close() }()
	bodyBytes, err := io.ReadAll(resp.Body)
	if err != nil {
		t.Fatalf("read body failed: %v", err)
	}
	_ = bodyBytes
	if resp.StatusCode != 101 {
		t.Fatalf("status: got %d want 101", resp.StatusCode)
	}
	if !strings.Contains(resp.Header.Get(`Sec-WebSocket-Accept`), `s3pPLMBiTxaQ9kYGzzhZRbK+xOo=`) {
		t.Fatalf("header %s mismatch: got %q want to contain %q", `Sec-WebSocket-Accept`, resp.Header.Get(`Sec-WebSocket-Accept`), `s3pPLMBiTxaQ9kYGzzhZRbK+xOo=`)
	}
	if !strings.Contains(resp.Header.Get(`Upgrade`), `websocket`) {
		t.Fatalf("header %s mismatch: got %q want to contain %q", `Upgrade`, resp.Header.Get(`Upgrade`), `websocket`)
	}
}
